@startuml
!theme plain

class "CreditAccount" as CreditAccount {
  + ...someAttribute
  + applyMonthlyInterest()
  + applyMonthlyChange()
  + ...someOtherMethod()
}

class "DebitAccount" as DebitAccount {
  + ...someAttribute
  + applyMonthlyInterest()
  + deactivateIfUnderBalanced()
  + applyMonthlyChange()
  + ...someOtherMethod()
}

class "PayrollAccount" as PayrollAccount {
  + ...someAttribute
  + applyMonthlyChange()
  + ...someMethod()
}

class "Bank" as Bank {
  + accounts: [Account]
  + applyAllMonthlyChanges()
}

interface "Account" as Account {
  + applyMonthlyChange()
}

CreditAccount ..|> Account
DebitAccount ..|> Account
PayrollAccount ..|> Account

Bank --|> Account

note right of Bank
  applyAllMonthlyChanges() {
    ...
    for every account a in accounts {
      a.applyMonthlyChange()
    }
  }
end note

@enduml
